 {"id":"charmed_rust-1k7n","title":"Implement PTY/Terminal Session Handling","description":"# Implement PTY/Terminal Session Handling

## Objective
Implement PTY (pseudo-terminal) allocation and terminal session management for SSH connections.

## Implementation Details

### PTY Handle
```rust
use portable_pty::{native_pty_system, PtySize, PtyPair, CommandBuilder};

pub struct PtyHandle {
    master: Box<dyn MasterPty + Send>,
    reader: Box<dyn std::io::Read + Send>,
    writer: Box<dyn std::io::Write + Send>,
    size: PtySize,
}

impl PtyHandle {
    pub fn new(term: &str, cols: u16, rows: u16) -> Result<Self, WishError> {
        let pty_system = native_pty_system();
        let size = PtySize {
            rows,
            cols,
            pixel_width: 0,
            pixel_height: 0,
        };

        let pair = pty_system.openpty(size)?;
        log::debug!("PTY allocated: {}x{} term={}", cols, rows, term);

        Ok(Self {
            master: pair.master,
            reader: pair.master.try_clone_reader()?,
            writer: pair.master.take_writer()?,
            size,
        })
    }

    pub fn resize(&mut self, cols: u16, rows: u16) -> Result<(), WishError> {
        self.size.cols = cols;
        self.size.rows = rows;
        self.master.resize(self.size)?;
        log::debug!("PTY resized to {}x{}", cols, rows);
        Ok(())
    }

    pub fn write(&mut self, data: &[u8]) -> Result<usize, WishError> {
        Ok(self.writer.write(data)?)
    }

    pub fn read(&mut self, buf: &mut [u8]) -> Result<usize, WishError> {
        Ok(self.reader.read(buf)?)
    }
}
```

### Terminal Session
```rust
pub struct TerminalSession {
    pub id: SessionId,
    pub pty: Option<PtyHandle>,
    pub term_type: String,
    pub env: HashMap<String, String>,
    pub window_size: WindowSize,
}

#[derive(Clone, Copy)]
pub struct WindowSize {
    pub cols: u16,
    pub rows: u16,
    pub pixel_width: u16,
    pub pixel_height: u16,
}

impl TerminalSession {
    pub fn new(id: SessionId) -> Self {
        Self {
            id,
            pty: None,
            term_type: "xterm-256color".to_string(),
            env: HashMap::new(),
            window_size: WindowSize { cols: 80, rows: 24, pixel_width: 0, pixel_height: 0 },
        }
    }

    pub fn allocate_pty(&mut self, term: &str, size: WindowSize) -> Result<(), WishError> {
        self.term_type = term.to_string();
        self.window_size = size;
        self.pty = Some(PtyHandle::new(term, size.cols, size.rows)?);
        log::info!("PTY allocated for session {}", self.id);
        Ok(())
    }
}
```

### Handler Integration
```rust
impl Handler for ConnectionHandler {
    async fn pty_request(
        &mut self,
        channel: ChannelId,
        term: &str,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        modes: &[(Pty, u32)],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::debug!("PTY request: term={} size={}x{}", term, col_width, row_height);

        let size = WindowSize {
            cols: col_width as u16,
            rows: row_height as u16,
            pixel_width: pix_width as u16,
            pixel_height: pix_height as u16,
        };

        self.session.allocate_pty(term, size)?;
        session.request_success();
        Ok(())
    }

    async fn window_change_request(
        &mut self,
        channel: ChannelId,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::debug!("Window change: {}x{}", col_width, row_height);

        if let Some(ref mut pty) = self.session.pty {
            pty.resize(col_width as u16, row_height as u16)?;
        }
        Ok(())
    }
}
```

