### 2. Theme Consistency Tests
```rust
#[test]
fn test_theme_consistency_across_blocks() {
    let markdown = r#"
\`\`\`rust
fn a() {}
\`\`\`

Some text in between.

\`\`\`rust
fn b() {}
\`\`\`
"#;

    let output = render(markdown);

    // Both `fn` keywords should have the same color
    let fn_indices: Vec<_> = output.match_indices("fn").collect();
    assert!(fn_indices.len() >= 2);

    // Extract the color codes before each `fn`
    let get_color_before = |idx: usize| {
        let prefix = &output[..idx];
        prefix.rfind("\x1b[").map(|start| &prefix[start..idx])
    };

    let color1 = get_color_before(fn_indices[0].0);
    let color2 = get_color_before(fn_indices[1].0);

    assert_eq!(color1, color2, "Same tokens should have same colors");
}
