    fn test_io_error_through_full_stack() {
        use std::io;

        // Simulate IO error that propagates up
        fn load_and_render_file(path: &str) -> Result<String, BubbleteaError> {
            let content = std::fs::read_to_string(path)?;  // IO error
            let rendered = glamour::render(&content)?;     // Render error
            Ok(rendered)
        }

        let result = load_and_render_file("/nonexistent/file.md");
        assert!(result.is_err());

        let err = result.unwrap_err();
        // IO error should be in the source chain
        let mut current: &dyn std::error::Error = &err;
        let mut found_io = false;
        while let Some(source) = current.source() {
            if source.downcast_ref::<io::Error>().is_some() {
                found_io = true;
                break;
            }
            current = source;
        }
        assert!(found_io, "IO error should be in source chain");
    }
