#[test]
fn test_full_application_error_handling() {
    use bubbletea::{Model, Program, Cmd};

    struct TestApp {
        error: Option<String>,
    }

    enum Msg {
        LoadFile(String),
        Error(BubbleteaError),
    }

    impl Model for TestApp {
        type Message = Msg;

        fn update(&mut self, msg: Msg) -> Cmd<Msg> {
            match msg {
                Msg::LoadFile(path) => {
                    Cmd::perform(
                        async move { std::fs::read_to_string(&path) },
                        |result| match result {
                            Ok(content) => Msg::LoadFile(content),
                            Err(e) => Msg::Error(e.into()),
                        }
                    )
                }
                Msg::Error(e) => {
                    self.error = Some(format!("{}", e));
                    Cmd::none()
                }
            }
        }

        fn view(&self) -> String {
            match &self.error {
                Some(e) => format!("Error: {}", e),
                None => "OK".to_string(),
            }
        }
    }

    // Test error flow through application
    let mut app = TestApp { error: None };
    app.update(Msg::Error(io::Error::new(io::ErrorKind::NotFound, "test").into()));

    assert!(app.error.is_some());
    assert!(app.view().contains("Error"));
}
